define half @select_fcmp_nnan_nsz_ogt_negzero(half %x) {
  %gtzero = fcmp ogt half %x, 0xH8000
  %negx = fsub fast half 0xH0000, %x
  %fabs = select i1 %gtzero, half %x, half %negx
  ret half %fabs
}

